        if (s1.empty() || s2.empty() || n1 == 0 || n2 == 0) {
            return 0;
        }
        int j = 0;
        int count = 0;
        int repeatCount = 0;
        vector<int> s1Index(s1.size() + 1, 0);
        vector<int> s2Count(s1.size() + 1, 0);
